import{_ as a,o,c as t,ag as r}from"./chunks/framework.D9bIGSBm.js";const g=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"reference/faq.md","filePath":"reference/faq.md"}'),s={name:"reference/faq.md"};function n(l,e,i,h,d,c){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><p>本页收录使用中的高频疑问。若未找到你需要的答案，请前往 <a href="/docs/reference/troubleshooting.html">故障排查</a> 查看具体问题的解决指引。</p><hr><h3 id="loongcode-是免费的吗-需要什么账号" tabindex="-1">LoongCode 是免费的吗？需要什么账号？ <a class="header-anchor" href="#loongcode-是免费的吗-需要什么账号" aria-label="Permalink to &quot;LoongCode 是免费的吗？需要什么账号？&quot;">​</a></h3><p>LoongCode 应用本身可从 GitHub Releases 免费下载，源码仓库公开发布。</p><p>使用 AI 功能需要本机安装 Claude CLI 或 Codex CLI，AI 服务的费用（如 API 调用计费、订阅计划等）由各 CLI 对应的供应商决定，与 LoongCode 本身无关，请参阅你所使用的 CLI 文档了解具体计费规则。</p><hr><h3 id="检测不到-claude-cli-怎么办" tabindex="-1">检测不到 Claude CLI 怎么办？ <a class="header-anchor" href="#检测不到-claude-cli-怎么办" aria-label="Permalink to &quot;检测不到 Claude CLI 怎么办？&quot;">​</a></h3><p>常见原因是 CLI 未安装或安装路径不在系统 PATH 中。处理步骤：</p><ol><li>前往<strong>设置 → 依赖管理</strong>，查看 Claude CLI 的检测状态，可在此直接安装。</li><li>若已安装但仍无法识别，可在<strong>设置 → 常规 → CLI 命令</strong>中手动填写可执行文件的完整路径。</li></ol><p>详见 <a href="/docs/reference/troubleshooting.html#cli-未被识别--任务无法启动">故障排查 — CLI 未被识别</a> 与 <a href="/docs/guide/prerequisites.html">前置依赖</a>。</p><hr><h3 id="claude-和-codex-任务可以同时用吗" tabindex="-1">Claude 和 Codex 任务可以同时用吗？ <a class="header-anchor" href="#claude-和-codex-任务可以同时用吗" aria-label="Permalink to &quot;Claude 和 Codex 任务可以同时用吗？&quot;">​</a></h3><p>可以。每个任务在创建时可独立选择使用 Claude CLI 或 Codex CLI，两者之间互不影响，可同时运行多个不同 CLI 的任务。此能力自 v0.7.0 起支持。</p><p>详见 <a href="/docs/features/tasks-and-workspaces.html">任务与工作区</a> 及 <a href="/docs/settings/cli.html">CLI 与任务配置</a>。</p><hr><h3 id="我的对话数据存在哪里" tabindex="-1">我的对话数据存在哪里？ <a class="header-anchor" href="#我的对话数据存在哪里" aria-label="Permalink to &quot;我的对话数据存在哪里？&quot;">​</a></h3><p>所有任务记录和设置文件保存在本机的数据目录中：</p><ul><li><strong>Windows：</strong> <code>%APPDATA%\\com.loongcode.desktop\\</code></li><li><strong>macOS：</strong> <code>~/Library/Application Support/com.loongcode.desktop/</code></li></ul><p>数据库文件为目录下的 <code>loongcode.db</code>。你可以在<strong>设置 → 常规 → 数据目录</strong>中查看当前路径；修改路径后，应用会自动把数据迁移到新位置并重新加载。</p><p>详见 <a href="/docs/settings/general.html">常规设置</a>。</p><hr><h3 id="自动更新支持哪些平台" tabindex="-1">自动更新支持哪些平台？ <a class="header-anchor" href="#自动更新支持哪些平台" aria-label="Permalink to &quot;自动更新支持哪些平台？&quot;">​</a></h3><p><strong>Windows</strong> 支持应用内自动更新——当有新版本时，右上角会显示更新徽标，点击并确认重启即可完成升级。</p><p><strong>macOS</strong> 请手动从 <a href="https://github.com/LoongCode0/loongcode-release/releases/latest" target="_blank" rel="noreferrer">GitHub Releases（LoongCode0/loongcode-release）</a> 下载最新的 <code>.dmg</code> 文件覆盖安装；应用内自动更新的平台支持范围以官方发布说明为准。</p><p>详见 <a href="/docs/guide/installation.html">安装 LoongCode</a>。</p><hr><h3 id="macos-提示「无法验证开发者」怎么办" tabindex="-1">macOS 提示「无法验证开发者」怎么办？ <a class="header-anchor" href="#macos-提示「无法验证开发者」怎么办" aria-label="Permalink to &quot;macOS 提示「无法验证开发者」怎么办？&quot;">​</a></h3><p>这是 macOS Gatekeeper 的安全提示，并非应用本身的问题。解决方法：</p><ul><li><strong>方式一：</strong> 在 Finder 中找到 LoongCode.app，按住 <code>Control</code> 键并单击（或右键），选择<strong>打开</strong>，在弹出对话框中确认打开。</li><li><strong>方式二：</strong> 在终端中运行以下命令移除隔离属性，之后正常双击启动：</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xattr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Applications/LoongCode.app</span></span></code></pre></div><hr><h3 id="怎么切换界面语言或主题" tabindex="-1">怎么切换界面语言或主题？ <a class="header-anchor" href="#怎么切换界面语言或主题" aria-label="Permalink to &quot;怎么切换界面语言或主题？&quot;">​</a></h3><p>前往<strong>设置 → 常规</strong>：</p><ul><li><strong>语言：</strong> 在&quot;语言&quot;下拉列表中选择中文或 English，切换后立即生效。</li><li><strong>主题：</strong> 在&quot;主题&quot;下拉列表中选择任一配色方案，切换即时生效。</li></ul><p>详见 <a href="/docs/settings/general.html">常规设置</a>。</p><hr><h3 id="归档的任务去哪了-怎么找回" tabindex="-1">归档的任务去哪了，怎么找回？ <a class="header-anchor" href="#归档的任务去哪了-怎么找回" aria-label="Permalink to &quot;归档的任务去哪了，怎么找回？&quot;">​</a></h3><p>归档任务不会被删除，仍保存在本地数据库中。找回方式：</p><p>在左侧任务栏的任务列表区域，点击<strong>任务 / 归档</strong>标签切换到<strong>归档</strong>视图，即可看到所有已归档任务。点击任意归档任务即可重新打开。</p><p>详见 <a href="/docs/features/tasks-and-workspaces.html">任务与工作区</a>。</p><hr><h3 id="上下文满了怎么办" tabindex="-1">上下文满了怎么办？ <a class="header-anchor" href="#上下文满了怎么办" aria-label="Permalink to &quot;上下文满了怎么办？&quot;">​</a></h3><p>有两种处理方式：</p><ol><li><strong>自动压缩（推荐开启）：</strong> 在<strong>设置 → 常规 → 自动压缩</strong>中开启后，上下文接近上限时应用会自动执行压缩摘要并继续任务。</li><li><strong>手动压缩：</strong> 在对话面板底部工具栏点击压缩按钮，手动触发摘要压缩。</li></ol><p>此外，自 v0.3.1 起支持上下文超限自动恢复，超限产生的错误会被自动处理。</p><p>详见 <a href="/docs/features/conversation.html">对话面板</a>。</p><hr><h3 id="如何重新打开新手引导" tabindex="-1">如何重新打开新手引导？ <a class="header-anchor" href="#如何重新打开新手引导" aria-label="Permalink to &quot;如何重新打开新手引导？&quot;">​</a></h3><p>前往<strong>设置 → 常规 → 使用引导</strong>区块：</p><ul><li>点击<strong>从头重看</strong>按钮可重新播放完整的 5 章引导。</li><li>每章右侧的<strong>重看</strong>按钮可单独重放某一章节。</li></ul><p>详见 <a href="/docs/settings/general.html">常规设置</a>。</p><hr><h3 id="token-用量在哪里看" tabindex="-1">token 用量在哪里看？ <a class="header-anchor" href="#token-用量在哪里看" aria-label="Permalink to &quot;token 用量在哪里看？&quot;">​</a></h3><p>前往<strong>设置 → 使用统计</strong>，可查看历史 token 消耗数据。</p><p>详见 <a href="/docs/features/usage-stats.html">使用统计</a>。</p><hr><h3 id="支持-linux-吗" tabindex="-1">支持 Linux 吗？ <a class="header-anchor" href="#支持-linux-吗" aria-label="Permalink to &quot;支持 Linux 吗？&quot;">​</a></h3><p>目前 LoongCode 仅发布了 <strong>Windows（x64 / ARM64）</strong> 和 <strong>macOS（Universal）</strong> 版本，暂未发布 Linux 安装包。如有 Linux 支持需求，请持续关注官方发布渠道。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/reference/shortcuts.html">快捷键一览</a> — 常用键盘操作速查</li><li><a href="/docs/reference/troubleshooting.html">故障排查</a> — 遇到具体问题时的解决指引</li></ul>',62)])])}const u=a(s,[["render",n]]);export{g as __pageData,u as default};
